TMDB_CACHE_TTL    = 86400   # 24 h — dados considerados frescos
TMDB_CACHE_STALE  = 43200   # 12 h — inicia refresh em background se passado esse tempo
_tmdb_bg_refresh  = False   # flag: refresh em andamento

def get_tmdb_cache(allow_stale=False):
    """Return cached TMDB data.
    allow_stale=True: return even if older than TTL (used for background refresh).
    """
    if TMDB_CACHE_FILE.exists():
        try:
            raw  = json_mod.loads(TMDB_CACHE_FILE.read_text(encoding="utf-8"))
            age  = time.time() - raw.get("timestamp", 0)
            data = raw.get("data", {})
            if data and (age < TMDB_CACHE_TTL or allow_stale):
                return data
        except Exception:
            pass
    return {}

def _maybe_refresh_cache_bg():
    """Trigger a background cache refresh if data is stale (>12h) but not expired (<24h)."""
    global _tmdb_bg_refresh
    if _tmdb_bg_refresh:
        return  # already running
    if not TMDB_CACHE_FILE.exists():
        return
    try:
        raw = json_mod.loads(TMDB_CACHE_FILE.read_text(encoding="utf-8"))
        age = time.time() - raw.get("timestamp", 0)
        if TMDB_CACHE_STALE < age < TMDB_CACHE_TTL:
            import threading as _th
            _tmdb_bg_refresh = True
            def _bg():
                global _tmdb_bg_refresh
                try:
                    fetch_all_tmdb_data(force=True)
                finally:
                    _tmdb_bg_refresh = False
            _th.Thread(target=_bg, daemon=True).start()
    except Exception:
        pass

def set_tmdb_cache(data):
    try:
        TMDB_CACHE_FILE.write_text(json_mod.dumps({
            "timestamp": time.time(),
            "data": data
        }))
    except:
        pass

