SERIES_RE = re.compile(r'^(.+?)\s+[ST](\d{1,2})[\s_xXeE](\d{1,3})', re.I)
PIPE_RE   = re.compile(r'^(.+?)\s*\|\s*(?:EP|T)\d', re.I)
