def normalize_text(v):
    return unicodedata.normalize("NFKD", v or "").encode("ascii","ignore").decode("ascii").lower().strip()

def get_db():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    return conn

def placeholder_image(seed, w=640, h=360):
    return f"https://picsum.photos/seed/{abs(hash(seed))%999999}/{w}/{h}"

def sanitize_channel_title(title):
    raw = (title or "").strip()
    if not raw:
        return "Canal"
    if any(token in raw for token in ('tvg-logo="', 'group-title="', 'pltv-subgroup="')):
        parts = [p.strip() for p in raw.split(",") if p.strip()]
        if parts:
            raw = parts[-1]
    raw = raw.replace("[24H] ", "").replace("[24h] ", "").replace('[24H]', '').replace('[24h]', '')
    raw = re.sub(r'\s+', ' ', raw).strip(' -"')
    return raw or "Canal"

def normalize_group(group):
    n = normalize_text(group)
    if n.startswith("canais") or n.startswith("radio"): return "Canais"
    if "[24h]" in n or "24 horas" in n: return "Canais"
    if n.startswith("show"): return "Filmes"
    for cat, rules in CATEGORY_RULES.items():
        if any(r in n for r in rules): return cat
    return group.strip() or "Canais"

def extract_series_name(titulo):
    m = SERIES_RE.match(titulo or "")
    if m: return m.group(1).strip()
    m2 = PIPE_RE.match(titulo or "")
    if m2: return m2.group(1).strip()
    return ""

def extract_episode_number(titulo):
    m = EP_NUM_RE.search(titulo or "")
    return int(m.group(1)) if m else None

def extract_season_number(titulo):
    m = SEASON_RE.search(titulo or "")
    return int(m.group(1)) if m else None

def is_adulto(titulo, subgrupo, group):
    """Detect adult/XXX content."""
    check = ((titulo or "") + " " + (subgrupo or "") + " " + (group or "")).lower()
    if any(fp in check for fp in ADULTO_FALSE_POSITIVES):
        return False
    return any(kw in check for kw in ADULTO_KEYWORDS)

def get_streaming_category(titulo, subgrupo, group):
    """Detect streaming category from title/group."""
    check = ((titulo or "") + " " + (subgrupo or "") + " " + (group or "")).lower()
    for platform, keywords in STREAMING_PLATFORMS.items():
        if any(kw in check for kw in keywords):
            return platform
    return None

def is_medicina(titulo, subgrupo):
    check = ((titulo or "") + " " + (subgrupo or "")).lower()
    if any(fp in check for fp in MEDICINA_FALSE_POSITIVES): return False
    return any(kw in check for kw in MEDICINA_KEYWORDS)

def validate_url(v):
    return bool(re.match(r"^https?://", v or "", re.I))

def validate_proxy_url(url):
    if not validate_url(url): return False
    if PROXY_WHITELIST:
        parsed = urllib.parse.urlparse(url)
        domain = parsed.netloc.lower().split(":")[0]
        return any(domain == w or domain.endswith("." + w) for w in PROXY_WHITELIST)
    return True

def is_live_stream(link):
    p = (link or "").lower()
    return ".m3u8" in p or p.endswith(".ts") or p.endswith(".mpd") or "/live/" in p or "/stream/" in p

def build_player_data(link):
    parsed = urllib.parse.urlparse(link or "")
    path = parsed.path.lower()
    ext = path.rsplit(".", 1)[-1] if "." in path else ""
    is_hls = ext == "m3u8" or "m3u8" in link.lower()
    is_ts  = ext == "ts"
    is_dash = ext == "mpd" or "mpd" in link.lower()
    mime_map = {
        "mp4":"video/mp4","m4v":"video/mp4","webm":"video/webm",
        "ogg":"video/ogg","ogv":"video/ogg",
        "m3u8":"application/vnd.apple.mpegurl",
        "mpd":"application/dash+xml",
        "ts":"video/mp2t","aac":"audio/aac","mp3":"audio/mpeg",
    }
    mime = mime_map.get(ext, "video/mp4")
    return {
        "mode": "video",
        "direct_url": link,
        "proxy_url": url_for("proxy_media", url=link),
        "label": ext.upper() if ext else "Stream",
        "mime": mime,
        "is_hls": is_hls,
        "is_ts": is_ts,
        "is_dash": is_dash,
        "is_live": is_hls or is_ts or is_dash,
    }

# ── TMDB cover resolver (called lazily by frontend) ───────────────────────
# In-memory cover cache: titulo -> (url | None, timestamp)
# TTL: 6 horas. Max 5000 entradas (LRU simples via insertion order).
_cover_cache     = {}
_COVER_CACHE_TTL = 21600   # 6 h
_COVER_CACHE_MAX = 5000

def _cover_cache_get(key):
    entry = _cover_cache.get(key)
    if entry is None:
        return None  # miss
    url, ts = entry
    if time.time() - ts > _COVER_CACHE_TTL:
        _cover_cache.pop(key, None)
        return None  # expired
    return url  # hit (may be empty string = confirmed not found)

def _cover_cache_set(key, url):
    if len(_cover_cache) >= _COVER_CACHE_MAX:
        # Evict oldest 500 entries
        for k in list(_cover_cache.keys())[:500]:
            _cover_cache.pop(k, None)
    _cover_cache[key] = (url, time.time())

def _clean_title_for_search(titulo):
    """Remove quality tags, year suffixes and noise from title for search."""
    q = re.sub(r'\[(?:FHD|HD|SD|4K|H265|HDR|HEVC|UHD|WEBDL|BLURAY|BDRIP)[^\]]*\]', '', titulo, flags=re.I)
    q = re.sub(r'\b(?:FHD|[0-9]+p)\b', '', q, flags=re.I)
    q = re.sub(r'\s*\(\d{4}\)\s*$', '', q)
    q = re.sub(r'\s*\[S\d+\]\s*', '', q)
    q = re.sub(r'\[24[Hh]\]\s*', '', q)
    q = re.sub(r'\s+', ' ', q).strip()
    return q


def _get_tmdb_token():
    """Return Bearer token if available, else None."""
    token = os.getenv("TMDB_READ_TOKEN", "").strip()
    if not token:
        env_path = BASE_DIR / ".env"
        if env_path.exists():
            for line in env_path.read_text(encoding="utf-8").splitlines():
                if line.startswith("TMDB_READ_TOKEN="):
                    token = line.split("=", 1)[1].strip().strip('"').strip("'")
    return token or None

def _http_get_json(url, timeout=6):
    """Simple HTTP GET returning parsed JSON or None."""
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "PinguimV6/1.0"})
        with urllib.request.urlopen(req, timeout=timeout) as r:
            return json_mod.loads(r.read())
    except Exception:
        return None

def _tmdb_get_json(url, timeout=6):
    """TMDB HTTP GET — prefers Bearer token auth, falls back to api_key in URL."""
    token = _get_tmdb_token()
    headers = {"User-Agent": "PinguimV6/1.0", "Accept": "application/json"}
    if token:
        headers["Authorization"] = f"Bearer {token}"
        # Remove api_key from URL when using Bearer (cleaner)
        url = re.sub(r'[?&]api_key=[^&]*', '', url).rstrip('?&')
        if '?' not in url:
            url = url  # keep as is
    for attempt in range(3):
        try:
            req = urllib.request.Request(url, headers=headers)
            with urllib.request.urlopen(req, timeout=timeout) as r:
                return json_mod.loads(r.read())
        except urllib.error.HTTPError as e:
            if e.code == 429:
                time.sleep(2 ** attempt + 1)
            else:
                return None
        except Exception:
            if attempt < 2:
                time.sleep(0.5)
    return None


def _cover_from_tmdb(query, media_type, api_key, lang="pt-BR"):
    """Try TMDB search. Uses Bearer token if available, else api_key. Returns poster URL or None."""
    if not query:
        return None
    endpoint = "/search/movie" if media_type == "movie" else "/search/tv"
    params   = {"query": query, "language": lang, "include_adult": "false"}
    if api_key:
        params["api_key"] = api_key
    url  = f"https://api.themoviedb.org/3{endpoint}?{urllib.parse.urlencode(params)}"
    data = _tmdb_get_json(url)
    if not data or not data.get("results"):
        return None
    # Score: popularity + exact title match bonus
    ql = query.lower()
    def _score(r):
        nm = (r.get("title") or r.get("name") or "").lower()
        return (50 if nm == ql else 0) + min(r.get("popularity", 0), 30) + (10 if r.get("poster_path") else 0)
    best = max(data["results"], key=_score)
    if best.get("poster_path"):
        return f"https://image.tmdb.org/t/p/w500{best['poster_path']}"
    return None


def _cover_from_omdb(query):
    """Try OMDB free API (no key needed for basic poster lookup). Returns poster URL or None."""
    # OMDB free tier: search by title, grab Poster field
    params = urllib.parse.urlencode({"t": query, "type": "movie", "plot": "short", "r": "json"})
    data = _http_get_json(f"https://www.omdbapi.com/?{params}")
    if data and data.get("Response") == "True":
        poster = data.get("Poster", "")
        if poster and poster != "N/A":
            return poster
    # Try TV
    params = urllib.parse.urlencode({"t": query, "type": "series", "plot": "short", "r": "json"})
    data = _http_get_json(f"https://www.omdbapi.com/?{params}")
    if data and data.get("Response") == "True":
        poster = data.get("Poster", "")
        if poster and poster != "N/A":
            return poster
    return None


def _cover_from_itunes(query, media_type):
    """Try iTunes Search API (public, no key). Returns artwork URL or None."""
    entity = "movie" if media_type == "movie" else "tvShow"
    params = urllib.parse.urlencode({"term": query, "entity": entity, "limit": "5", "country": "BR"})
    data = _http_get_json(f"https://itunes.apple.com/search?{params}")
    if data and data.get("results"):
        item = data["results"][0]
        art = item.get("artworkUrl100") or item.get("artworkUrl60")
        if art:
            # Upgrade to higher resolution
            return art.replace("100x100bb", "600x600bb").replace("60x60bb", "600x600bb")
    return None


def _normalize_ascii(text):
    """Convert accented chars to ASCII for broader search matching."""
    return unicodedata.normalize("NFKD", text).encode("ascii", "ignore").decode("ascii").strip()


def tmdb_cover_for(titulo, media_type="movie"):
    """
    Fetch poster using cascading sources:
      1. TMDB pt-BR  (Bearer token preferred over api_key)
      2. TMDB en-US
      3. TMDB en-US with ASCII title (strips accents)
      4. OMDB free API
      5. iTunes Search API
    Uses in-memory LRU cache with 6h TTL.
    """
    cache_key = f"{media_type}:{titulo}"
    cached = _cover_cache_get(cache_key)
    if cached is not None:      # "" = confirmed miss (still valid for TTL period)
        return cached or None

    # Resolve credentials (Bearer token preferred)
    api_key = get_tmdb_api_key()

    query = _clean_title_for_search(titulo)
    if not query or len(query) < 2:
        _cover_cache_set(cache_key, "")
        return None

    ascii_query = _normalize_ascii(query)
    result_url  = None

    # ── 1 & 2. TMDB pt-BR then en-US ─────────────────────────────────────
    if api_key or _get_tmdb_token():
        result_url = _cover_from_tmdb(query, media_type, api_key, lang="pt-BR")
        if not result_url:
            result_url = _cover_from_tmdb(query, media_type, api_key, lang="en-US")

    # ── 3. TMDB en-US + ASCII title ───────────────────────────────────────
    if not result_url and ascii_query and ascii_query != query.lower():
        result_url = _cover_from_tmdb(ascii_query, media_type, api_key, lang="en-US")

    # ── 4. OMDB ───────────────────────────────────────────────────────────
    if not result_url:
        result_url = _cover_from_omdb(query)
    if not result_url and ascii_query and ascii_query != query.lower():
        result_url = _cover_from_omdb(ascii_query)

    # ── 5. iTunes ─────────────────────────────────────────────────────────
    if not result_url:
        result_url = _cover_from_itunes(query, media_type)
    if not result_url and ascii_query and ascii_query != query.lower():
        result_url = _cover_from_itunes(ascii_query, media_type)

    _cover_cache_set(cache_key, result_url or "")
    return result_url

def get_tmdb_api_key():
    api_key = os.getenv("TMDB_API_KEY", "").strip()
    if not api_key:
        env_path = BASE_DIR / ".env"
        if env_path.exists():
            for line in env_path.read_text().splitlines():
                if line.startswith("TMDB_API_KEY="):
                    api_key = line.split("=",1)[1].strip().strip('"').strip("'")
    return api_key

def tmdb_request(endpoint, params):
    api_key = get_tmdb_api_key()
    if not api_key:
        return None
    params["api_key"] = api_key
    params["language"] = "pt-BR"
    url = f"https://api.themoviedb.org/3{endpoint}?{urllib.parse.urlencode(params)}"
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "PinguimV6/1.0"})
        with urllib.request.urlopen(req, timeout=10) as r:
            return json_mod.loads(r.read())
    except:
        return None

def parse_tmdb_result(r, media_type="movie"):
    if not r.get("poster_path"):
        return None
    return {
        "titulo": r.get("title") or r.get("name", ""),
        "capa": f"https://image.tmdb.org/t/p/w500{r['poster_path']}",
        "backdrop": f"https://image.tmdb.org/t/p/w1280{r.get('backdrop_path', '')}" if r.get("backdrop_path") else "",
        "ano": str(r.get("release_date", "")[:4]) if r.get("release_date") else (str(r.get("first_air_date", "")[:4]) if r.get("first_air_date") else ""),
        "genero": "Filmes" if media_type == "movie" else "Series",
        "tmdb_id": r.get("id", 0),
        "media_type": media_type,
        "nota": round(r.get("vote_average", 0), 1),
        "sinopse": r.get("overview", "")[:150],
    }

def fetch_all_tmdb_data(force=False):
    """Fetch TMDB data. Uses disk cache unless force=True or cache is empty/expired."""
    cache = get_tmdb_cache()
    if not force and cache and len(cache.get("popular_movies", [])) > 0:
        return cache
    
    api_key = get_tmdb_api_key()
    if not api_key:
        print("[TMDB] Sem API key - usando dados de demonstração")
        return TMDB_FALLBACK_DATA
    
    data = {
        "popular_movies": [],
        "popular_tv": [],
        "top_rated_movies": [],
        "top_rated_tv": [],
        "upcoming": [],
        "trending_movies": [],
        "trending_tv": [],
        "now_playing": [],
        "action_movies": [],
        "comedy_movies": [],
        "horror_movies": [],
        "romance_movies": [],
        "sci_fi_movies": [],
        "animation_movies": [],
    }
    
    # Popular Movies - fetch 5 pages (~100 movies)
    for page in range(1, 6):
        result = tmdb_request("/movie/popular", {"page": page})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item and item["nota"] >= 4.0:
                    data["popular_movies"].append(item)
        else:
            break
    
    # Popular TV - fetch 4 pages
    for page in range(1, 5):
        result = tmdb_request("/tv/popular", {"page": page})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "tv")
                if item and item["nota"] >= 4.0:
                    data["popular_tv"].append(item)
        else:
            break
    
    # Top Rated Movies - fetch 5 pages (~100 movies)
    for page in range(1, 6):
        result = tmdb_request("/movie/top_rated", {"page": page})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["top_rated_movies"].append(item)
        else:
            break
    
    # Top Rated TV - fetch 4 pages
    for page in range(1, 5):
        result = tmdb_request("/tv/top_rated", {"page": page})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "tv")
                if item:
                    data["top_rated_tv"].append(item)
        else:
            break
    
    # Upcoming Movies
    result = tmdb_request("/movie/upcoming", {})
    if result and result.get("results"):
        for r in result["results"][:20]:
            item = parse_tmdb_result(r, "movie")
            if item:
                data["upcoming"].append(item)
    
    # Now Playing (in theaters)
    for page in range(1, 3):
        result = tmdb_request("/movie/now_playing", {"page": page})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["now_playing"].append(item)
        else:
            break
    
    # Trending Movies - fetch 5 pages
    for page in range(1, 6):
        result = tmdb_request("/trending/movie/week", {"page": page})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["trending_movies"].append(item)
        else:
            break
    
    # Trending TV - fetch 4 pages
    for page in range(1, 5):
        result = tmdb_request("/trending/tv/week", {"page": page})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "tv")
                if item:
                    data["trending_tv"].append(item)
        else:
            break
    
    # Genre-based discovery (Action - 28)
    for page in range(1, 3):
        result = tmdb_request("/discover/movie", {"page": page, "with_genres": "28", "sort_by": "popularity.desc"})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["action_movies"].append(item)
        else:
            break
    
    # Genre discovery (Comedy - 35)
    for page in range(1, 3):
        result = tmdb_request("/discover/movie", {"page": page, "with_genres": "35", "sort_by": "popularity.desc"})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["comedy_movies"].append(item)
        else:
            break
    
    # Genre discovery (Horror - 27)
    for page in range(1, 3):
        result = tmdb_request("/discover/movie", {"page": page, "with_genres": "27", "sort_by": "popularity.desc"})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["horror_movies"].append(item)
        else:
            break
    
    # Genre discovery (Romance - 10749)
    for page in range(1, 3):
        result = tmdb_request("/discover/movie", {"page": page, "with_genres": "10749", "sort_by": "popularity.desc"})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["romance_movies"].append(item)
        else:
            break
    
    # Genre discovery (Sci-Fi - 878)
    for page in range(1, 3):
        result = tmdb_request("/discover/movie", {"page": page, "with_genres": "878", "sort_by": "popularity.desc"})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["sci_fi_movies"].append(item)
        else:
            break
    
    # Genre discovery (Animation - 16)
    for page in range(1, 3):
        result = tmdb_request("/discover/movie", {"page": page, "with_genres": "16", "sort_by": "popularity.desc"})
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, "movie")
                if item:
                    data["animation_movies"].append(item)
        else:
            break
    
    set_tmdb_cache(data)
    return data

def get_popular_from_tmdb(media_type="movie", limit=20):
    data = fetch_all_tmdb_data()
    key = "popular_movies" if media_type == "movie" else "popular_tv"
    items = data.get(key, [])
    # Shuffle daily for variety
    if items:
        day_seed = datetime.date.today().toordinal()
        random.Random(day_seed).shuffle(items)
    return items[:limit]

def get_top_rated_tmdb(media_type="movie", limit=20):
    data = fetch_all_tmdb_data()
    key = "top_rated_movies" if media_type == "movie" else "top_rated_tv"
    items = data.get(key, [])
    # Shuffle daily for variety
    if items:
        day_seed = datetime.date.today().toordinal()
        random.Random(day_seed).shuffle(items)
    return items[:limit]

def get_upcoming_tmdb(limit=20, include_future=False):
    """Return upcoming movies. By default only returns already-released titles.
    Pass include_future=True to also get unreleased ones (they will have is_future=True)."""
    data = fetch_all_tmdb_data()
    items = data.get("upcoming", [])
    today = datetime.date.today().isoformat()

    released = []
    future   = []
    for item in items:
        rd = item.get("release_date") or item.get("ano") or ""
        if rd and rd > today:
            item = dict(item)
            item["is_future"] = True
            future.append(item)
        else:
            released.append(item)

    if released:
        day_seed = datetime.date.today().toordinal()
        random.Random(day_seed).shuffle(released)

    if include_future:
        return (released + future)[:limit]
    return released[:limit]

def get_trending_tmdb(media_type="movie", limit=20):
    data = fetch_all_tmdb_data()
    key = "trending_movies" if media_type == "movie" else "trending_tv"
    items = data.get(key, [])
    # Shuffle daily for variety
    if items:
        day_seed = datetime.date.today().toordinal()
        random.Random(day_seed).shuffle(items)
    return items[:limit]

def get_now_playing_tmdb(limit=20):
    data = fetch_all_tmdb_data()
    items = data.get("now_playing", [])
    # Shuffle daily for variety
    if items:
        day_seed = datetime.date.today().toordinal()
        random.Random(day_seed).shuffle(items)
    return items[:limit]

def get_on_the_air_tmdb(limit=20):
    result = tmdb_request("/tv/on_the_air", {"page": 1})
    items = []
    if result and result.get("results"):
        for r in result["results"][:limit]:
            item = parse_tmdb_result(r, "tv")
            if item:
                items.append(item)
    return items

def get_genre_movies(genre, limit=20, media_type="movie"):
    """Fetch movies/TV by genre from TMDB using the discover endpoint."""
    genre_id = TMDB_GENRE_IDS.get(genre)
    if not genre_id:
        return []
    
    items = []
    pages_needed = max(1, (limit + 19) // 20)  # TMDB returns ~20 per page
    
    for page in range(1, pages_needed + 1):
        if media_type == "movie":
            result = tmdb_request("/discover/movie", {
                "page": page,
                "with_genres": str(genre_id),
                "sort_by": "popularity.desc",
                "vote_count.gte": 50
            })
        else:
            result = tmdb_request("/discover/tv", {
                "page": page,
                "with_genres": str(genre_id),
                "sort_by": "popularity.desc",
                "vote_count.gte": 50
            })
        
        if result and result.get("results"):
            for r in result["results"]:
                item = parse_tmdb_result(r, media_type)
                if item:
                    items.append(item)
        else:
            break
        
        if len(items) >= limit:
            break
    
    # Se não encontrou via API, usar fallback
    if not items:
        # Para TV genres que já tem _tv no nome, usar direto
        if media_type == "tv" and genre.endswith("_tv"):
            fallback_key = genre
        elif media_type == "tv":
            fallback_key = f"{genre}_tv"
        else:
            fallback_key = f"{genre}_movies"
        fallback_items = TMDB_FALLBACK_DATA.get(fallback_key, [])
        # Shuffle para variety daily - usa seed baseado no dia
        shuffled = fallback_items.copy()
        day_seed = datetime.date.today().toordinal()
        random.Random(day_seed).shuffle(shuffled)
        items = shuffled[:limit]
    
    return items[:limit]

def get_tv_by_genre(genre, limit=20):
    """Fetch TV shows by genre."""
    return get_genre_movies(genre, limit, media_type="tv")

