@app.route("/api/cover")
def api_cover():
    """Multi-source cover resolver (TMDB pt-BR -> TMDB en-US -> OMDB -> iTunes)."""
    # No auth required — public read-only endpoint
    titulo = request.args.get("t", "").strip()
    media  = request.args.get("m", "movie")  # movie or tv
    if not titulo:
        return jsonify({"url": ""})
    url = tmdb_cover_for(titulo, media)
    if url:
        link = request.args.get("link", "")
        if link:
            try:
                conn = get_db()
                dead_conditions = ("capa LIKE '%lgfp.one%' OR capa LIKE '%goo.gl%' OR "
                                   "capa LIKE '%t.co/%' OR capa LIKE '%bit.ly%' OR "
                                   "capa LIKE '%tinyurl.com%' OR capa='' OR capa IS NULL")
                conn.execute(f"UPDATE filmes SET capa=? WHERE link=? AND ({dead_conditions})", (url, link))
                conn.commit(); conn.close()
            except Exception:
                pass
        return jsonify({"url": url})
    return jsonify({"url": ""})

@app.route("/api/covers/batch", methods=["POST"])
def api_covers_batch():
    """Batch cover resolver — multi-source (TMDB pt-BR/en + OMDB + iTunes). Up to 50 per call."""
    # No auth required — public read-only endpoint
    try:
        import concurrent.futures as _cf
        items = request.get_json(silent=True) or []
        # Deduplicate
        seen = {}
        unique = []
        for item in items[:50]:
            titulo = (item.get("titulo") or "").strip()
            media  = item.get("media_type", "movie")
            if titulo and titulo not in seen:
                seen[titulo] = media
                unique.append((titulo, media))

        results = {}

        def resolve(t_m):
            titulo, media = t_m
            return titulo, tmdb_cover_for(titulo, media)

        # Resolve in parallel (up to 8 threads) for speed
        with _cf.ThreadPoolExecutor(max_workers=8) as executor:
            for titulo, url in executor.map(resolve, unique):
                results[titulo] = url or ""

        return jsonify({"results": results})
    except Exception as e:
        return jsonify({"results": {}, "error": str(e)})

