@app.route("/api/tmdb/search")
def api_tmdb_search():
    """Search TMDB for movies and TV shows."""
    if not authenticated(): return jsonify({"error": "Unauthorized"}), 401
    query = request.args.get("q", "").strip()
    media = request.args.get("type", "movie")
    page = int(request.args.get("page", 1))
    
    if not query:
        return jsonify({"results": []})
    
    endpoint = "/search/movie" if media == "movie" else "/search/tv"
    result = tmdb_request(endpoint, {"query": query, "page": page})
    
    if result and result.get("results"):
        items = []
        for r in result["results"]:
            item = parse_tmdb_result(r, media)
            if item:
                items.append(item)
        return jsonify({"results": items, "total": result.get("total_results", 0)})
    
    return jsonify({"results": [], "total": 0})

@app.route("/api/tmdb/discover")
def api_tmdb_discover():
    """Discover TMDB movies by genre or category."""
    if not authenticated(): return jsonify({"error": "Unauthorized"}), 401
    category = request.args.get("category", "popular")
    page = int(request.args.get("page", 1))
    
    if category == "trending":
        return jsonify({"results": get_trending_tmdb("movie", limit=100)})
    elif category == "top_rated":
        return jsonify({"results": get_top_rated_tmdb("movie", limit=100)})
    elif category == "upcoming":
        return jsonify({"results": get_upcoming_tmdb(limit=100)})
    elif category == "now_playing":
        return jsonify({"results": get_now_playing_tmdb(limit=100)})
    elif category in ("action", "comedy", "horror", "romance", "sci_fi", "animation"):
        return jsonify({"results": get_genre_movies(category, limit=100)})
    else:
        return jsonify({"results": get_popular_from_tmdb("movie", limit=100)})

def rewrite_m3u8_playlist(content, base_url):
    out = []
    for raw in content.splitlines():
        line = raw.strip()
        if not line or line.startswith("#"):
            if 'URI="' in raw:
                def repl(m):
                    return f'URI="{url_for("proxy_media", url=urllib.parse.urljoin(base_url, m.group(1)))}"'
                raw = re.sub(r'URI="([^"]+)"', repl, raw)
            out.append(raw)
            continue
        out.append(url_for("proxy_media", url=urllib.parse.urljoin(base_url, line)))
    return "\n".join(out)

def init_db():
    conn = get_db(); c = conn.cursor()
    c.execute("""CREATE TABLE IF NOT EXISTS usuarios (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT NOT NULL UNIQUE, password TEXT NOT NULL,
        email TEXT DEFAULT '',
        avatar TEXT DEFAULT 'penguin',
        dias_acesso INTEGER DEFAULT 30,
        playlist_url TEXT DEFAULT '',
        access_token TEXT DEFAULT '',
        is_admin INTEGER DEFAULT 0,
        data_registro DATETIME DEFAULT CURRENT_TIMESTAMP)""")
    # Migrate columns for existing installs
    u_existing = {row[1] for row in c.execute("PRAGMA table_info(usuarios)").fetchall()}
    for col, typedef in [
        ("email",        "TEXT DEFAULT ''"),
        ("avatar",       "TEXT DEFAULT 'penguin'"),
        ("playlist_url", "TEXT DEFAULT ''"),
        ("access_token", "TEXT DEFAULT ''"),
        ("is_admin",     "INTEGER DEFAULT 0"),
    ]:
        if col not in u_existing:
            c.execute(f"ALTER TABLE usuarios ADD COLUMN {col} {typedef}")
    c.execute("""CREATE TABLE IF NOT EXISTS filmes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        titulo TEXT NOT NULL, capa TEXT NOT NULL, link TEXT NOT NULL,
        genero TEXT DEFAULT '', subgrupo TEXT DEFAULT '',
        ano INTEGER DEFAULT 0, duracao TEXT DEFAULT '',
        sinopse TEXT DEFAULT '', fonte TEXT DEFAULT '',
        tmdb_id INTEGER DEFAULT 0, backdrop TEXT DEFAULT '')""")
    c.execute("""CREATE TABLE IF NOT EXISTS user_media_cache (
        user_id INTEGER NOT NULL,
        media_id INTEGER NOT NULL,
        titulo TEXT DEFAULT '',
        poster_url TEXT DEFAULT '',
        series_poster_url TEXT DEFAULT '',
        genero TEXT DEFAULT '',
        subgrupo TEXT DEFAULT '',
        updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        PRIMARY KEY (user_id, media_id))""")
    c.execute("CREATE INDEX IF NOT EXISTS idx_genero   ON filmes(genero)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_subgrupo ON filmes(subgrupo)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_titulo   ON filmes(titulo)")
    # Migrate columns BEFORE creating index that depends on them
    existing = {row[1] for row in c.execute("PRAGMA table_info(filmes)").fetchall()}
    for col, typedef in [
        ("tmdb_id", "INTEGER DEFAULT 0"),
        ("backdrop", "TEXT DEFAULT ''"),
        ("canal_categoria", "TEXT DEFAULT ''"),
        ("canal_prioridade", "INTEGER DEFAULT 0"),
        ("canal_status", "TEXT DEFAULT ''"),
        ("canal_checked_at", "TEXT DEFAULT ''"),
        ("canal_diagnostico", "TEXT DEFAULT ''"),
    ]:
        if col not in existing:
            c.execute(f"ALTER TABLE filmes ADD COLUMN {col} {typedef}")
    c.execute("CREATE INDEX IF NOT EXISTS idx_tmdb_id  ON filmes(tmdb_id)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_canal_categoria ON filmes(canal_categoria)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_canal_status ON filmes(canal_status)")
    demo = c.execute("SELECT id,password FROM usuarios WHERE username='demo'").fetchone()
    if not demo:
        c.execute("INSERT INTO usuarios (username,password,dias_acesso) VALUES (?,?,?)",
                  ("demo", generate_password_hash("demo123"), 30))
    elif not str(demo["password"]).startswith(("pbkdf2:","scrypt:")):
        c.execute("UPDATE usuarios SET password=? WHERE id=?",
                  (generate_password_hash("demo123"), demo["id"]))
    conn.commit(); conn.close()

def parse_m3u(content, fonte=""):
    """Parse M3U content. Works on full string (legacy) or chunked."""
    canais = []; lines = content.splitlines(); i = 0
    while i < len(lines):
        line = lines[i].strip()
        if not line.startswith("#EXTINF"):
            i += 1; continue
        logo  = (re.search(r'tvg-logo="([^"]*)"',    line) or [None,""])[1]
        group = (re.search(r'group-title="([^"]*)"', line) or [None,"Canais"])[1]
        sub   = (re.search(r'pltv-subgroup="([^"]*)"',line) or [None,""])[1]
        name  = sanitize_channel_title((re.search(r',(.+)$', line) or [None,"Sem titulo"])[1].strip())
        url = ""; j = i + 1
        while j < len(lines):
            cand = lines[j].strip()
            if cand and not cand.startswith("#"):
                url = cand; i = j; break
            j += 1
        if url and name and validate_url(url):
            cgroup = normalize_group(group)
            subgrupo = sub.strip() if sub.strip() else extract_series_name(name)
            capa = logo.strip() if logo and logo.strip() else placeholder_image(name)
            if is_medicina(name, subgrupo) and cgroup in ("Seriado","Filmes","Documentários"):
                cgroup = "Medicina"
            elif cgroup == "Filmes":
                streaming_cat = get_streaming_category(name, subgrupo, group)
                if streaming_cat:
                    cgroup = streaming_cat
            canais.append({"titulo":name,"capa":capa,"link":url,
                           "genero":cgroup,"subgrupo":subgrupo,"fonte":fonte})
        i += 1
    return canais

def parse_m3u_stream(url_or_file, fonte="", batch_size=500):
    """Generator: yield batches of parsed channels without loading full file into memory.
    Handles URLs (streaming download) and file objects."""
    import io

    # User-Agent que imita players IPTV reais — servidores IPTV bloqueiam scrapers
    IPTV_UA = (
        "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 "
        "(KHTML, like Gecko) Chrome/120.0.0.0 Mobile Safari/537.36"
    )

    def _iter_lines(source):
        """Yield lines from URL (streaming) or file-like object."""
        if isinstance(source, str) and source.startswith(("http://","https://")):
            req = urllib.request.Request(source, headers={
                "User-Agent": IPTV_UA,
                "Accept": "*/*",
                "Accept-Language": "pt-BR,pt;q=0.9,en;q=0.8",
                "Connection": "keep-alive",
            })
            with urllib.request.urlopen(req, timeout=120) as r:
                buf = ""
                while True:
                    chunk = r.read(65536).decode("utf-8","ignore")
                    if not chunk: break
                    buf += chunk
                    while "\n" in buf:
                        line, buf = buf.split("\n", 1)
                        yield line
                if buf.strip():
                    yield buf
        else:
            # File-like or string content
            content = source if isinstance(source, str) else source.read().decode("utf-8","ignore")
            for line in content.splitlines():
                yield line

    batch = []
    pending_extinf = None

    for raw_line in _iter_lines(url_or_file):
        line = raw_line.strip()
        if line.startswith("#EXTINF"):
            pending_extinf = line
        elif pending_extinf and line and not line.startswith("#"):
            url = line
            if validate_url(url):
                logo  = (re.search(r'tvg-logo="([^"]*)"',    pending_extinf) or [None,""])[1]
                group = (re.search(r'group-title="([^"]*)"', pending_extinf) or [None,"Canais"])[1]
                sub   = (re.search(r'pltv-subgroup="([^"]*)"',pending_extinf) or [None,""])[1]
                name  = sanitize_channel_title((re.search(r',(.+)$', pending_extinf) or [None,"Sem titulo"])[1].strip())
                cgroup   = normalize_group(group)
                subgrupo = sub.strip() if sub.strip() else extract_series_name(name)
                capa     = logo.strip() if logo and logo.strip() else placeholder_image(name)
                if is_medicina(name, subgrupo) and cgroup in ("Seriado","Filmes","Documentários"):
                    cgroup = "Medicina"
                elif cgroup == "Filmes":
                    sc = get_streaming_category(name, subgrupo, group)
                    if sc: cgroup = sc
                batch.append({"titulo":name,"capa":capa,"link":url,
                               "genero":cgroup,"subgrupo":subgrupo,"fonte":fonte})
                if len(batch) >= batch_size:
                    yield batch
                    batch = []
            pending_extinf = None

    if batch:
        yield batch

# ── Import jobs (background) ────────────────────────────────────────────────
import threading as _threading
_import_jobs = {}   # job_id → {"status","total","done","error"}

def _run_import_job(job_id, source, fonte, limpar):
    """Background thread: stream-parse M3U and import in batches."""
    global _import_jobs
    _import_jobs[job_id] = {"status":"running","total":0,"done":0,"error":None}
    try:
        conn = get_db(); c = conn.cursor()
        if limpar:
            c.execute("DELETE FROM filmes")
            conn.commit()
        first_batch = True
        for batch in parse_m3u_stream(source, fonte=fonte, batch_size=500):
            batch = fill_series_covers(batch)
            c.executemany(
                "INSERT OR IGNORE INTO filmes (titulo,capa,link,genero,subgrupo,fonte) "
                "VALUES (:titulo,:capa,:link,:genero,:subgrupo,:fonte)", batch)
            conn.commit()
            _import_jobs[job_id]["done"] += len(batch)
            _import_jobs[job_id]["total"] = _import_jobs[job_id]["done"]
        conn.close()
        _import_jobs[job_id]["status"] = "done"
    except Exception as e:
        _import_jobs[job_id]["status"] = "error"
        _import_jobs[job_id]["error"]  = str(e)



def _is_dead_cover(url):
    """Return True if the URL is a placeholder/dead image."""
    if not url or not url.strip():
        return True
    dead = ("lgfp.one","goo.gl","t.co/","bit.ly","tinyurl.com","picsum.photos","placehold","undefined","null")
    return any(d in url for d in dead)

def fill_series_covers(canais):
    """Force every episode in a series to share the same best-quality cover (series poster)."""
    # Pass 1 — find the best (non-dead) cover per subgrupo
    cover_map = {}
    for item in canais:
        sg = item.get("subgrupo", "")
        capa = item.get("capa", "")
        if sg and not _is_dead_cover(capa):
            cover_map.setdefault(sg, capa)

    # Pass 2 — apply the best cover to ALL episodes in the series (not just broken ones)
    for item in canais:
        sg = item.get("subgrupo", "")
        if sg and sg in cover_map:
            item["capa"] = cover_map[sg]

    return canais

def import_canais(canais, limpar=False):
    canais = fill_series_covers(canais)
    conn = get_db(); c = conn.cursor()
    if limpar: c.execute("DELETE FROM filmes")
    c.executemany("INSERT INTO filmes (titulo,capa,link,genero,subgrupo,fonte) VALUES (:titulo,:capa,:link,:genero,:subgrupo,:fonte)", canais)
    conn.commit()
    total = c.execute("SELECT COUNT(*) FROM filmes").fetchone()[0]
    conn.close(); return total

def authenticated(): return "user_id" in session

def build_page_url(page):
    args = request.args.to_dict(flat=True); args["p"] = page
    return f"{request.path}?{urlencode(args)}"

# ── Garante que o banco é inicializado mesmo rodando via gunicorn ──
_db_initialized = False
@app.before_request
def ensure_db():
    global _db_initialized
    if not _db_initialized:
        init_db()
        _db_initialized = True

@app.context_processor
def inject_layout():
    user_info = None
    if authenticated():
        # Use session-cached user_info to avoid a DB hit on every request
        ui = session.get("_user_info_cache")
        if not ui:
            conn = get_db()
            u = conn.execute("SELECT * FROM usuarios WHERE id=?", (session["user_id"],)).fetchone()
            conn.close()
            if u:
                import datetime as _dt
                reg = u["data_registro"] or ""
                try:
                    reg_date = _dt.datetime.strptime(reg[:19], "%Y-%m-%d %H:%M:%S")
                    validade = reg_date + _dt.timedelta(days=int(u["dias_acesso"] or 30))
                    val_str  = validade.strftime("%d/%m/%Y")
                    expired  = validade < _dt.datetime.utcnow()
                except Exception:
                    val_str = "—"; expired = False
                ui = {
                    "username": u["username"],
                    "email":    u["email"]  or "",
                    "avatar":   u["avatar"] or "penguin",
                    "validade": val_str,
                    "expired":  expired,
                    "is_admin": bool(u["is_admin"]),
                }
                session["_user_info_cache"] = ui
        user_info = ui
    return {
        "section_config": SECTION_CONFIG,
        "username":  session.get("username"),
        "user_info": user_info,
        "build_page_url": build_page_url,
        "extract_episode_number": extract_episode_number,
        "extract_season_number":  extract_season_number,
    }

@app.route("/", methods=["GET","POST"])
def login():
    if authenticated(): return redirect(url_for("home"))
    error = None
    if request.method == "POST":
        u = request.form.get("username","").strip()
        p = request.form.get("password","").strip()
        conn = get_db()
        user = conn.execute("SELECT * FROM usuarios WHERE username=?", (u,)).fetchone()
        conn.close()
        if user and check_password_hash(user["password"], p):
            session["user_id"] = user["id"]; session["username"] = user["username"]
            # Auto-import playlist vinculada ao usuario (sempre que fizer login)
            playlist = (user["playlist_url"] or "").strip()
            if playlist:
                already_running = any(j.get("status") == "running" for j in _import_jobs.values())
                if not already_running:
                    import uuid as _uuid
                    job_id = _uuid.uuid4().hex
                    session["last_import_job"] = job_id
                    t = _threading.Thread(target=_run_import_job,
                        args=(job_id, playlist, playlist, True), daemon=True)
                    t.start()
            return redirect(url_for("home"))
        error = "Usuario ou senha incorretos."
    return render_template("login.html", error=error)

@app.route("/logout")
def logout():
    session.clear(); return redirect(url_for("login"))

