    conn = get_db()
    has_admin = conn.execute("SELECT COUNT(*) FROM usuarios WHERE is_admin=1").fetchone()[0]
    if has_admin:
        conn.close()
        return Response("""<!DOCTYPE html><html><head><meta charset='UTF-8'>
        <title>Setup</title><style>body{background:#0d0d1a;color:#eee;font-family:sans-serif;
        display:flex;align-items:center;justify-content:center;height:100vh;margin:0}
        .box{background:#13131f;border:1px solid rgba(255,255,255,.1);border-radius:12px;
        padding:2rem;text-align:center;max-width:400px}
        a{color:#e50914}</style></head>
        <body><div class='box'><div style='font-size:2rem'>🔒</div>
        <h2>Setup já concluído</h2>
        <p style='color:#aaa'>Já existe um administrador cadastrado.<br>
        Esta rota está desativada por segurança.</p>
        <a href='/'>← Voltar ao início</a></div></body></html>""",
        content_type="text/html")

    error = ""
    if request.method == "POST":
        username = request.form.get("username","").strip()
        password = request.form.get("password","").strip()
        confirm  = request.form.get("confirm","").strip()
        codigo   = request.form.get("codigo","").strip()

        # Código secreto fixo para impedir acesso indevido
        SETUP_CODE = os.getenv("SETUP_CODE", "pinguim2026")

        if codigo != SETUP_CODE:
            error = "Código de ativação incorreto."
        elif not username or not password:
            error = "Preencha todos os campos."
        elif password != confirm:
            error = "As senhas não coincidem."
        elif len(password) < 6:
            error = "A senha deve ter pelo menos 6 caracteres."
        else:
            # Verificar se o usuário já existe
            u = conn.execute("SELECT id FROM usuarios WHERE username=?", (username,)).fetchone()
            if u:
                # Promover existente a admin
                conn.execute("UPDATE usuarios SET is_admin=1, password=? WHERE username=?",
                             (generate_password_hash(password), username))
            else:
                # Criar novo admin
                import secrets as _sec
                token = _sec.token_urlsafe(24)
                conn.execute(
                    "INSERT INTO usuarios (username,password,is_admin,access_token) VALUES (?,?,1,?)",
                    (username, generate_password_hash(password), token)
                )
            conn.commit()
            conn.close()
