@app.route("/api/user/avatar", methods=["POST"])
def api_set_avatar():
    if not authenticated(): return jsonify({"error":"auth"}), 401
    data = request.get_json(silent=True) or {}
    avatar = data.get("avatar","").strip()
    VALID = {"penguin","cat","robot","alien","ghost","star","fire","crown","diamond","ninja","wizard","bear","fox","lion","unicorn"}
    if avatar not in VALID: return jsonify({"error":"invalid"}), 400
    conn = get_db()
    conn.execute("UPDATE usuarios SET avatar=? WHERE id=?", (avatar, session["user_id"]))
    conn.commit(); conn.close()
    session.pop("_user_info_cache", None)  # invalidate cache so next request refreshes it
    return jsonify({"ok": True, "avatar": avatar})

@app.route("/api/trailer")
def api_trailer():
    """Fetch YouTube trailer key for a movie/show from TMDB."""
    if not authenticated():
        return jsonify({"error": "auth"}), 401
    tmdb_id   = request.args.get("id", "").strip()
    titulo    = request.args.get("t",  "").strip()
    mtype     = request.args.get("m",  "movie").strip()  # movie | tv
    return jsonify(fetch_tmdb_trailer_payload(tmdb_id=tmdb_id, titulo=titulo, mtype=mtype))

@app.route("/api/series-cover")
def api_series_cover():
    """Return the canonical (best) cover URL for a given subgrupo/series name."""
    if not authenticated(): return jsonify({"error":"auth"}), 401
    subgrupo = request.args.get("sg", "").strip()
    if not subgrupo:
        return jsonify({"cover": ""})
    conn = get_db()
    # Pick the first non-dead cover for this subgrupo
    dead_conditions = ("capa NOT LIKE '%lgfp.one%' AND capa NOT LIKE '%goo.gl%' "
                       "AND capa NOT LIKE '%picsum%' AND capa NOT LIKE '%placehold%' "
                       "AND capa != '' AND capa IS NOT NULL")
    row = conn.execute(
        f"SELECT capa FROM filmes WHERE subgrupo=? AND {dead_conditions} ORDER BY id LIMIT 1",
        (subgrupo,)
    ).fetchone()
    conn.close()
    return jsonify({"cover": row["capa"] if row else ""})

@app.route("/reimportar")
def reimportar():
    """Dispara reimportacao da playlist do usuario logado."""
    if not authenticated(): return redirect(url_for("login"))
    conn = get_db()
    u = conn.execute("SELECT playlist_url FROM usuarios WHERE id=?", (session["user_id"],)).fetchone()
    conn.close()
    playlist = (u["playlist_url"] or "").strip() if u else ""
    if not playlist:
        return redirect(url_for("importar_m3u"))
    already_running = any(j.get("status") == "running" for j in _import_jobs.values())
    if not already_running:
        import uuid as _uuid
        job_id = _uuid.uuid4().hex
        session["last_import_job"] = job_id
        t = _threading.Thread(target=_run_import_job,
            args=(job_id, playlist, playlist, True), daemon=True)
        t.start()
    return redirect(url_for("home"))

@app.route("/home")
def home():
    conn = get_db()
    hero_items = FEATURED_MOVIES + get_trending_tmdb("movie", limit=10)

    # TMDB sections — served from 24h disk cache; triggers background refresh if stale
    _maybe_refresh_cache_bg()
    home_sections = {
        "🎬 Filmes Populares": get_popular_from_tmdb("movie", limit=30),
        "📺 Séries Populares": get_popular_from_tmdb("tv",    limit=30),
    }
    futuros = [item for item in get_upcoming_tmdb(limit=60, include_future=True) if item.get("is_future")][:18]
    if futuros:
        home_sections["🗓 Em Breve"] = futuros

    total_geral = conn.execute("SELECT COUNT(*) FROM filmes").fetchone()[0]

    # Check if user has playlist and import status
    u = conn.execute("SELECT playlist_url FROM usuarios WHERE id=?", (session["user_id"],)).fetchone()
    user_playlist = (u["playlist_url"] or "").strip() if u else ""
    conn.close()

    # Active import job status
    last_job_id = session.get("last_import_job")
    import_status = _import_jobs.get(last_job_id) if last_job_id else None
    # Also check any running job
    if not import_status:
        running = [(jid, j) for jid, j in _import_jobs.items() if j.get("status") == "running"]
        if running:
            import_status = running[-1][1]
            last_job_id   = running[-1][0]

    return render_template("home.html",
                          hero_items=hero_items,
                          home_sections=home_sections,
                          canais_itens=[],
                          canais_total=0,
                          total_geral=total_geral,
                          user_playlist=user_playlist,
                          import_status=import_status,
                          import_job_id=last_job_id,
                          tmdb_configurado=bool(get_tmdb_api_key()))

@app.route("/serie/<path:nome_serie>")
def serie(nome_serie):
    if not authenticated(): return redirect(url_for("login"))
    conn = get_db()
    episodios = conn.execute(
        "SELECT * FROM filmes WHERE subgrupo=? ORDER BY titulo", (nome_serie,)
    ).fetchall()
    if not episodios: conn.close(); abort(404)
    genero = episodios[0]["genero"]
    cfg = SECTION_CONFIG.get(genero, {"icon":"📺","cor":"#f6ad55"})
    capa = next(
        (e["capa"] for e in episodios
         if e["capa"] and "picsum" not in (e["capa"] or "") and "lgfp.one" not in (e["capa"] or "")),
        next((e["capa"] for e in episodios if e["capa"]), "")
    )
    backdrop = next((e["backdrop"] for e in episodios if e["backdrop"]), "")
    sinopse  = next((e["sinopse"]  for e in episodios if e["sinopse"]),  "")
    ano      = next((e["ano"]      for e in episodios if e["ano"] and e["ano"] > 0), 0)
    temporadas = {}
    for ep in episodios:
        season_num = extract_season_number(ep["titulo"]) or 0
        temporadas.setdefault(season_num, []).append(ep)
    temporadas_sorted = sorted(temporadas.items())
    conn.close()
    return render_template("serie.html",
        nome_serie=nome_serie, episodios=episodios,
        temporadas=temporadas_sorted, genero=genero, cfg=cfg,
        capa=capa, backdrop=backdrop, sinopse=sinopse, ano=ano)

@app.route("/tmdb")
def tmdb_browse():
    """Browse all TMDB content."""
    if not authenticated(): return redirect(url_for("login"))
    category = request.args.get("cat", "popular")
    search_query = request.args.get("q", "").strip()
    
    categories = {
        "popular": {"title": "Filmes Populares", "icon": "⭐"},
        "trending": {"title": "Em Alta", "icon": "🔥"},
        "top_rated": {"title": "Mais Votados", "icon": "🏆"},
        "upcoming": {"title": "Lançamentos", "icon": "🎬"},
        "now_playing": {"title": "Nos Cinemas", "icon": "🎥"},
        "action": {"title": "Ação", "icon": "💥"},
        "comedy": {"title": "Comédia", "icon": "😂"},
        "horror": {"title": "Terror", "icon": "💀"},
        "romance": {"title": "Romance", "icon": "💕"},
        "sci_fi": {"title": "Ficção Científica", "icon": "🚀"},
        "animation": {"title": "Animação", "icon": "🎨"},
    }
    
    current_cat = categories.get(category, categories["popular"])
    
    if search_query:
        result = tmdb_request("/search/multi", {"query": search_query})
        items = []
        if result and result.get("results"):
            for r in result["results"]:
                if r.get("media_type") in ("movie", "tv") and r.get("poster_path"):
                    items.append({
                        "titulo": r.get("title") or r.get("name", ""),
                        "capa": f"https://image.tmdb.org/t/p/w500{r['poster_path']}",
                        "ano": str(r.get("release_date", "")[:4]) if r.get("release_date") else (str(r.get("first_air_date", "")[:4]) if r.get("first_air_date") else ""),
                        "genero": "Filmes" if r.get("media_type") == "movie" else "Series",
                        "nota": round(r.get("vote_average", 0), 1),
                        "media_type": r.get("media_type"),
                    })
    else:
        if category == "popular":
            items = get_popular_from_tmdb("movie", limit=100)
        elif category == "trending":
            items = get_trending_tmdb("movie", limit=100)
        elif category == "top_rated":
            items = get_top_rated_tmdb("movie", limit=100)
        elif category == "upcoming":
            items = get_upcoming_tmdb(limit=100)
        elif category == "now_playing":
            items = get_now_playing_tmdb(limit=100)
        elif category in ("action", "comedy", "horror", "romance", "sci_fi", "animation"):
            items = get_genre_movies(category, limit=100)
        else:
            items = get_popular_from_tmdb("movie", limit=100)
    
    return render_template("tmdb_browse.html", 
                          items=items, 
                          categories=categories,
                          current_cat=category,
                          current_cat_info=current_cat,
                          search_query=search_query)

