@app.route("/canais")
def canais():
    """Página dedicada de Canais Ao Vivo."""
    if not authenticated(): return redirect(url_for("login"))
    conn = get_db()
    busca = request.args.get("q", "").strip()
    pagina = max(1, int(request.args.get("p", 1)))
    por_pag = 60

    where = ["genero='Canais'"]
    params = []
    if busca:
        where.append("titulo LIKE ?")
        params.append(f"%{busca}%")
    wsql = "WHERE " + " AND ".join(where)
    rows = conn.execute(
        f"""SELECT * FROM filmes {wsql}
            ORDER BY canal_prioridade DESC, titulo ASC""",
        params
    ).fetchall()
    conn.close()

    enriched = [enrich_channel_row(r) for r in rows if is_relevant_live_channel(r)]
    if busca:
        busca_norm = normalize_text(busca)
        enriched = [r for r in enriched if busca_norm in normalize_text(r["titulo_limpo"])]

    visible = [r for r in enriched if (r.get("canal_status") or "") != "dead"]
    total = len(visible)
    offset = (pagina - 1) * por_pag
    itens = visible[offset:offset + por_pag]

    curated_sections = {}
    if not busca:
        for category in ("Abertos", "Esportes", "Noticias/Variedades"):
            section_rows = [r for r in visible if r["canal_categoria"] == category]
            curated_sections[category] = list(pick_best_channels(section_rows, limit_per_brand=1))[:12]

    total_pag = max(1, (total + por_pag - 1) // por_pag)
    return render_template("canais.html",
        itens=itens, total=total, busca=busca,
        pagina=pagina, total_pag=total_pag,
        curated_sections=curated_sections)

