@app.route("/api/watch-cache", methods=["GET", "POST"])
def api_watch_cache():
    if not authenticated():
        return jsonify({"error": "auth"}), 401
    user_id = session["user_id"]
    conn = get_db()

    if request.method == "POST":
        data = request.get_json(silent=True) or {}
        media_id = int(data.get("media_id") or 0)
        if not media_id:
            conn.close()
            return jsonify({"ok": False, "error": "media_id"}), 400
        poster = (data.get("poster_url") or "").strip()
        series_poster = (data.get("series_poster_url") or "").strip()
        titulo = (data.get("titulo") or "").strip()
        genero = (data.get("genero") or "").strip()
        subgrupo = (data.get("subgrupo") or "").strip()
        conn.execute("""
            INSERT INTO user_media_cache
            (user_id, media_id, titulo, poster_url, series_poster_url, genero, subgrupo, updated_at)
            VALUES (?,?,?,?,?,?,?,CURRENT_TIMESTAMP)
            ON CONFLICT(user_id, media_id) DO UPDATE SET
                titulo=excluded.titulo,
                poster_url=excluded.poster_url,
                series_poster_url=excluded.series_poster_url,
                genero=excluded.genero,
                subgrupo=excluded.subgrupo,
                updated_at=CURRENT_TIMESTAMP
        """, (user_id, media_id, titulo, poster, series_poster, genero, subgrupo))
        conn.commit()
        conn.close()
        return jsonify({"ok": True})

    raw = request.args.get("ids", "").strip()
    ids = [int(x) for x in raw.split(",") if x.strip().isdigit()]
    if not ids:
        conn.close()
        return jsonify({"items": []})
    rows = conn.execute(
        f"SELECT * FROM user_media_cache WHERE user_id=? AND media_id IN ({','.join('?'*len(ids))})",
        [user_id] + ids
    ).fetchall()
    conn.close()
    return jsonify({"items": [dict(r) for r in rows]})

@app.route("/secao/<categoria>")
def secao(categoria):
    if not authenticated(): return redirect(url_for("login"))
    cfg = SECTION_CONFIG.get(categoria, {"icon":"📁","cor":"7c8798"})
    busca    = request.args.get("q","").strip()
    subgrupo = request.args.get("sub","").strip()
    pagina   = max(1, int(request.args.get("p", 1)))
    por_pag  = 48
    conn = get_db()
    
    if categoria in TMDB_GENRES:
        tmdb_genres = TMDB_GENRES.get(categoria, [])
        tmdb_key = request.args.get("tmdb", "")
        tmdb_items = []
        
        if tmdb_key:
            is_tv = categoria in ("Series", "Seriado", "Medicina", "Documentários")
            
            if tmdb_key in TMDB_TV_FILTERS:
                tmdb_items = TMDB_TV_FILTERS[tmdb_key]()
            elif tmdb_key in TV_GENRE_KEYS:
                tmdb_items = get_tv_by_genre(tmdb_key, limit=100)
            elif tmdb_key == "trending":
                tmdb_items = get_trending_tmdb("tv" if is_tv else "movie", limit=100)
            elif tmdb_key == "top_rated":
                tmdb_items = get_top_rated_tmdb("tv" if is_tv else "movie", limit=100)
            elif tmdb_key == "upcoming":
                tmdb_items = get_upcoming_tmdb(limit=100)
            elif tmdb_key == "now_playing":
                tmdb_items = get_now_playing_tmdb(limit=100)
            elif tmdb_key == "popular":
                tmdb_items = get_popular_from_tmdb("tv" if is_tv else "movie", limit=100)
            elif tmdb_key in TMDB_GENRE_IDS:
                tmdb_items = get_genre_movies(tmdb_key, limit=100)
        
        if not busca and not subgrupo and not tmdb_key:
            if categoria in TMDB_TV_FILTERS:
                tmdb_key = list(TMDB_TV_FILTERS.keys())[0]
                tmdb_items = TMDB_TV_FILTERS[tmdb_key]()
            else:
                tmdb_key = "trending"
                is_tv = categoria in ("Series", "Seriado", "Medicina", "Documentários")
                tmdb_items = get_trending_tmdb("tv" if is_tv else "movie", limit=100)
        
        return render_template("secao.html",
            categoria=categoria, cfg=cfg, itens=[], mode="tmdb",
            destaque=None, subgrupos=[], subgrupo_sel="",
            busca=busca, pagina=1, total_pag=1, total=0, formato="",
            tmdb_genres=tmdb_genres, tmdb_key=tmdb_key, tmdb_items=tmdb_items)
    
    if categoria in ("Seriado", "Medicina") and not subgrupo and not busca:
        where_extra = f"genero='{categoria}' AND subgrupo != ''"
        total = conn.execute(f"SELECT COUNT(DISTINCT subgrupo) FROM filmes WHERE {where_extra}").fetchone()[0]
        offset = (pagina - 1) * por_pag
        itens = conn.execute(f"""
            SELECT MIN(id) as id, subgrupo as titulo, MIN(capa) as capa,
                   genero, subgrupo, COUNT(*) as ep_count
            FROM filmes WHERE {where_extra}
            GROUP BY subgrupo ORDER BY subgrupo LIMIT ? OFFSET ?
        """, (por_pag, offset)).fetchall()
        mode = "series"
    else:
        where = ["genero=?"]; params = [categoria]
        if busca:
            where.append("(titulo LIKE ? OR subgrupo LIKE ?)"); params.extend([f"%{busca}%", f"%{busca}%"])
        if subgrupo:
            where.append("subgrupo=?"); params.append(subgrupo)
        wsql = "WHERE " + " AND ".join(where)
        total = conn.execute(f"SELECT COUNT(*) FROM filmes {wsql}", params).fetchone()[0]
        offset = (pagina-1)*por_pag
        itens = conn.execute(f"SELECT * FROM filmes {wsql} ORDER BY titulo LIMIT ? OFFSET ?",
                              params+[por_pag, offset]).fetchall()
        mode = "items"
    subgrupos = [r[0] for r in conn.execute(
        "SELECT DISTINCT subgrupo FROM filmes WHERE genero=? AND subgrupo!='' ORDER BY subgrupo", (categoria,)
    ).fetchall()]
    destaque = conn.execute("SELECT * FROM filmes WHERE genero=? ORDER BY RANDOM() LIMIT 1", (categoria,)).fetchone()
    conn.close()
    total_pag = max(1, (total + por_pag - 1) // por_pag)
    return render_template("secao.html",
        categoria=categoria, cfg=cfg, itens=itens, mode=mode,
        destaque=destaque, subgrupos=subgrupos, subgrupo_sel=subgrupo,
        busca=busca, pagina=pagina, total_pag=total_pag, total=total, formato="",
        tmdb_genres=[], tmdb_key="", tmdb_items=[])

