@app.route("/assistir/<int:id_filme>")
def assistir(id_filme):
    if not authenticated(): return redirect(url_for("login"))
    conn = get_db()
    filme = conn.execute("SELECT * FROM filmes WHERE id=?", (id_filme,)).fetchone()
    if not filme: conn.close(); abort(404)
    proximos = []; prev_item = next_item = None
    if filme["subgrupo"]:
        todos = conn.execute(
            "SELECT * FROM filmes WHERE subgrupo=? ORDER BY titulo", (filme["subgrupo"],)
        ).fetchall()
        idx = next((i for i, e in enumerate(todos) if e["id"] == id_filme), None)
        if idx is not None:
            prev_item = todos[idx - 1] if idx > 0 else None
            next_item = todos[idx + 1] if idx < len(todos) - 1 else None
            proximos = [e for e in todos if e["id"] != id_filme]
    else:
        proximos = conn.execute(
            "SELECT * FROM filmes WHERE genero=? AND id!=? ORDER BY RANDOM() LIMIT 20",
            (filme["genero"], id_filme)
        ).fetchall()
    cfg = SECTION_CONFIG.get(filme["genero"], {"icon":"🎬","cor":"#ff5c38"})
    ep_num = extract_episode_number(filme["titulo"])
    resolved_cover = resolve_media_cover(conn, filme)
    # Canonical series cover: SQL picks the first non-dead cover for this subgrupo
    series_cover = resolved_cover or filme["capa"] or ""
    if filme["subgrupo"]:
        dead_cond = ("capa NOT LIKE '%lgfp.one%' AND capa NOT LIKE '%goo.gl%' "
                     "AND capa NOT LIKE '%picsum%' AND capa NOT LIKE '%placehold%' "
                     "AND capa != '' AND capa IS NOT NULL")
        best = conn.execute(
            f"SELECT capa FROM filmes WHERE subgrupo=? AND {dead_cond} ORDER BY id LIMIT 1",
            (filme["subgrupo"],)
        ).fetchone()
        if best and best["capa"]:
            series_cover = best["capa"]
    conn.close()
    return render_template("assistir.html", filme=filme, proximos=proximos,
                           cfg=cfg, player=build_player_data(filme["link"]),
                           prev_item=prev_item, next_item=next_item, ep_num=ep_num,
                           series_cover=series_cover, resolved_cover=resolved_cover)

def search_local_by_title(titulo, conn):
    """Smart search for a title in local database.
    Priority: 1) exact title  2) starts-with  3) contains (closest length)
              4) phrase pairs  5) keywords  6) subgrupo
    """
    stopwords = {
        'de','da','do','dos','das','a','o','os','as','um','uma','e',
        'the','an','of','in','on','at','to','for','with','by','from',
        'el','la','los','las','del','uno','una','y','en','por','para'
    }

    def _norm(s):
        s = re.sub(r'\[(?:FHD|HD|SD|4K|H265|HDR)[^\]]*\]', '', s, flags=re.I)
        s = re.sub(r'\s*\(\d{4}\)\s*$', '', s)
        s = re.sub(r'[^\w\s]', ' ', s)
        return ' '.join(s.lower().split())

    clean = _norm(titulo)
    orig  = titulo.strip()

    # 1. Exact full-title match
    exact = conn.execute(
        "SELECT * FROM filmes WHERE LOWER(TRIM(titulo)) = LOWER(TRIM(?)) COLLATE NOCASE LIMIT 1",
        (orig,)
    ).fetchone()
    if exact:
        return exact

    exact = conn.execute(
        "SELECT * FROM filmes WHERE LOWER(TRIM(titulo)) = ? COLLATE NOCASE LIMIT 1",
        (clean,)
    ).fetchone()
    if exact:
        return exact

    # 2. Starts-with match (shortest title = most specific)
    rows = conn.execute(
        "SELECT * FROM filmes WHERE titulo LIKE ? COLLATE NOCASE ORDER BY LENGTH(titulo) LIMIT 10",
        (f"{orig}%",)
    ).fetchall()
    if rows:
        return rows[0]

    rows = conn.execute(
        "SELECT * FROM filmes WHERE titulo LIKE ? COLLATE NOCASE ORDER BY LENGTH(titulo) LIMIT 10",
        (f"{clean}%",)
    ).fetchall()
    if rows:
        return rows[0]

    # 3. Contains full clean title — pick closest length to avoid wrong movie
    rows = conn.execute(
        "SELECT * FROM filmes WHERE titulo LIKE ? COLLATE NOCASE ORDER BY LENGTH(titulo) LIMIT 10",
        (f"%{clean}%",)
    ).fetchall()
    if rows:
        return min(rows, key=lambda r: abs(len(_norm(r['titulo'])) - len(clean)))

    # 4. Phrase pairs
    words = [w for w in clean.split() if len(w) > 3 and w.lower() not in stopwords]
    for i in range(len(words) - 1):
        phrase = f"{words[i]} {words[i+1]}"
        rows = conn.execute(
            "SELECT * FROM filmes WHERE titulo LIKE ? COLLATE NOCASE ORDER BY LENGTH(titulo) LIMIT 5",
            (f"%{phrase}%",)
        ).fetchall()
        if rows:
            return min(rows, key=lambda r: abs(len(_norm(r['titulo'])) - len(clean)))

    # 5. Individual keywords
    for word in words[:4]:
        rows = conn.execute(
            "SELECT * FROM filmes WHERE titulo LIKE ? COLLATE NOCASE ORDER BY titulo LIMIT 5",
            (f"%{word}%",)
        ).fetchall()
        if rows:
            for r in rows:
                if _norm(r['titulo']).startswith(word.lower()):
                    return r
            return rows[0]

    # 6. Subgrupo fallback (series)
    rows = conn.execute(
        "SELECT * FROM filmes WHERE subgrupo LIKE ? COLLATE NOCASE ORDER BY titulo LIMIT 5",
        (f"%{clean}%",)
    ).fetchall()
    if rows:
        return rows[0]

    return None

def normalize_match_text(value):
    value = unicodedata.normalize("NFKD", value or "").encode("ascii", "ignore").decode("ascii")
    value = re.sub(r"\[(?:FHD|HD|SD|4K|H265|HDR|HEVC|UHD|WEBDL|BLURAY|BDRIP)[^\]]*\]", " ", value, flags=re.I)
    value = re.sub(r"\(\d{4}\)", " ", value)
    value = re.sub(r"[^\w\s]", " ", value.lower())
    return " ".join(value.split())

def is_future_release_date(date_str):
    raw = (date_str or "").strip()[:10]
    if not raw:
        return False
    try:
        return datetime.date.fromisoformat(raw) > datetime.date.today()
    except Exception:
        return False

def format_release_date(date_str):
    raw = (date_str or "").strip()[:10]
    if not raw:
        return ""
    try:
        rd = datetime.date.fromisoformat(raw)
        meses = ["","Jan","Fev","Mar","Abr","Mai","Jun","Jul","Ago","Set","Out","Nov","Dez"]
        return f"{rd.day} de {meses[rd.month]} de {rd.year}"
    except Exception:
        return raw

def is_confident_local_match(query_title, filme):
    if not filme:
        return False
    query_norm = normalize_match_text(query_title)
    title_norm = normalize_match_text(filme["titulo"] or "")
    sub_norm   = normalize_match_text(filme["subgrupo"] or "")
    if not query_norm:
        return False
    variants = [v for v in (title_norm, sub_norm) if v]
    if query_norm in variants:
        return True
    if any(v.startswith(query_norm) or query_norm.startswith(v) for v in variants):
        return True
    query_tokens = {t for t in query_norm.split() if len(t) > 2}
    for variant in variants:
        tokens = {t for t in variant.split() if len(t) > 2}
        overlap = len(query_tokens & tokens)
        ratio = difflib.SequenceMatcher(None, query_norm, variant).ratio()
        if overlap >= max(2, min(len(query_tokens), 3)) and ratio >= 0.72:
            return True
    return False

def fetch_tmdb_trailer_payload(tmdb_id="", titulo="", mtype="movie"):
    """Fetch trailer/release metadata for a TMDB title."""
    api_key = get_tmdb_api_key()

    def _best_trailer(videos_data):
        if not videos_data:
            return None
        results = videos_data.get("results", [])
        for kind in ("Official Trailer", "Trailer", "Teaser", "Clip"):
            for v in results:
                if v.get("site") == "YouTube" and kind.lower() in v.get("name", "").lower():
                    return v["key"]
        for v in results:
            if v.get("site") == "YouTube":
                return v["key"]
        return None

    trailer_key  = None
    release_date = ""
    sinopse      = ""
    poster       = ""
    titulo_real  = titulo

    if api_key and tmdb_id:
        media_path = "movie" if mtype == "movie" else "tv"
        videos = tmdb_request(f"/{media_path}/{tmdb_id}/videos", {})
        trailer_key = _best_trailer(videos)
        details = tmdb_request(f"/{media_path}/{tmdb_id}", {})
        if details:
            release_date = details.get("release_date") or details.get("first_air_date") or ""
            sinopse      = details.get("overview", "")[:200]
            poster_path  = details.get("poster_path", "")
            if poster_path:
                poster = f"https://image.tmdb.org/t/p/w500{poster_path}"
            titulo_real  = details.get("title") or details.get("name") or titulo
    elif api_key and titulo:
        endpoint = "/search/movie" if mtype == "movie" else "/search/tv"
        res = tmdb_request(endpoint, {"query": titulo})
        if res and res.get("results"):
            found = res["results"][0]
            found_id = found.get("id")
            release_date = found.get("release_date") or found.get("first_air_date") or ""
            sinopse      = found.get("overview", "")[:200]
            titulo_real  = found.get("title") or found.get("name") or titulo
            pp = found.get("poster_path")
            if pp:
                poster = f"https://image.tmdb.org/t/p/w500{pp}"
            if found_id:
                media_path = "movie" if mtype == "movie" else "tv"
                videos = tmdb_request(f"/{media_path}/{found_id}/videos", {})
                trailer_key = _best_trailer(videos)
                tmdb_id = found_id

    release_fmt = ""
    if release_date:
        release_fmt = format_release_date(release_date)

    return {
        "tmdb_id":      int(tmdb_id or 0),
        "trailer_key":  trailer_key,
        "release_date": release_date[:10] if release_date else "",
        "release_fmt":  release_fmt,
        "sinopse":      sinopse,
        "poster":       poster,
        "titulo":       titulo_real,
        "has_api":      bool(api_key),
        "is_future":    is_future_release_date(release_date),
        "media_type":   mtype or "movie",
    }

def diagnose_stream_url(url):
    """Probe a stream URL and classify common IPTV failures."""
    if not validate_url(url):
        return {
            "ok": False,
            "kind": "invalid_url",
            "protocol": "unknown",
            "http_status": None,
            "content_type": "",
            "detail": "URL inválida ou ausente.",
            "recommendation": "Revise a origem M3U e o token do canal.",
        }

    parsed = urllib.parse.urlparse(url)
    path = parsed.path.lower()
    protocol = "dash" if path.endswith(".mpd") else ("hls" if ".m3u8" in path else ("mpeg-ts" if path.endswith(".ts") else "stream"))
    attempts = [
        ("HEAD", {"User-Agent": "Mozilla/5.0 (compatible; PinguimDiag/1.0)"}),
        ("GET",  {"User-Agent": "Mozilla/5.0 (compatible; PinguimDiag/1.0)", "Range": "bytes=0-0"}),
    ]
    last_error = None

    for method, headers in attempts:
        req = urllib.request.Request(url, method=method, headers=headers)
        try:
            with urllib.request.urlopen(req, timeout=12) as resp:
                content_type = resp.headers.get("Content-Type", "")
                status = getattr(resp, "status", 200)
                return {
                    "ok": 200 <= status < 300,
                    "kind": "ok",
                    "protocol": protocol,
                    "http_status": status,
                    "content_type": content_type,
                    "detail": f"Fonte respondeu via {method} com {status}.",
                    "recommendation": "Sinal acessível. Se o player falhar, a causa provável é compatibilidade do protocolo ou bloqueio intermitente.",
                }
        except urllib.error.HTTPError as exc:
            content_type = exc.headers.get("Content-Type", "") if exc.headers else ""
            kind = "http_error"
            detail = f"Origem respondeu HTTP {exc.code}."
            recommendation = "Verifique se a URL/token expirou ou se a lista M3U está desatualizada."
            if exc.code in (401, 403):
                kind = "auth"
                detail = f"Origem bloqueou a requisição com HTTP {exc.code}."
                recommendation = "Token, usuário/senha ou referrer da fonte provavelmente expirou ou foi bloqueado."
            elif exc.code == 404:
                kind = "not_found"
                detail = "Origem respondeu HTTP 404."
                recommendation = "O link do canal está quebrado ou removido na origem."
            return {
                "ok": False,
                "kind": kind,
                "protocol": protocol,
                "http_status": exc.code,
                "content_type": content_type,
                "detail": detail,
                "recommendation": recommendation,
            }
        except Exception as exc:
            last_error = exc

    err_txt = str(last_error or "").lower()
    kind = "timeout" if "timed out" in err_txt else "network"
    recommendation = "A origem está instável ou indisponível no momento."
    if "refused" in err_txt or "reset" in err_txt:
        recommendation = "A origem recusou a conexão. Pode haver bloqueio por IP ou servidor offline."
    return {
        "ok": False,
        "kind": kind,
        "protocol": protocol,
        "http_status": None,
        "content_type": "",
        "detail": f"Não foi possível validar a origem: {last_error!r}" if last_error else "Não foi possível validar a origem.",
        "recommendation": recommendation,
    }

def channel_quality_score(title):
    t = normalize_text(title)
    score = 0
    if "4k" in t:
        score += 400
    if "fhd" in t or "full hd" in t:
        score += 300
    elif "hd" in t:
        score += 200
    elif "sd" in t:
        score += 100
    if "h265" in t:
        score += 20
    if "hdr" in t:
        score += 10
    return score

def classify_channel_category(title):
    t = normalize_text(sanitize_channel_title(title))
    if not t:
        return "Outros"
    if any(x in t for x in ("radio", "fm ", " am ", "gaucha zh")):
        return "Irrelevante"
    if re.search(r'^\d{1,2}:\d{2}\s*-', t):
        return "Irrelevante"
    if any(x in t for x in (" espn", "espn ", "sportv", "premiere", "combate", "bandsports", "nba league", "nfl", "ufc", "dazn", "fox sports", "tnt sports", "paramount+ ao vivo")):
        return "Esportes"
    if any(x in t for x in ("globo", "sbt", "recordtv", "record tv", "record ", " band", "band ", "rede tv", "tv cultura", "gazeta")):
        return "Abertos"
    if any(x in t for x in ("cnn", "globonews", "globo news", "band news", "record news", "times brasil", "jp news", "jovem pan news", "news")):
        return "Noticias/Variedades"
    if any(x in t for x in ("discovery", "history", "tlc", "nat geo", "national geographic", "gnt", "multishow", "viva", "bis", "arte 1", "curta", "h&h", "home & health", "investigation discovery")):
        return "Noticias/Variedades"
    if any(x in t for x in ("[24h]", "24 horas", "s0", "s1", "s2", "s3", "s4", "s5")):
        return "Irrelevante"
    return "Outros"

def channel_brand_priority(title):
    t = normalize_text(sanitize_channel_title(title))
    priority = 0
    brand_rules = [
        ("globo", 1000), ("sbt", 980), ("recordtv", 960), ("record ", 960), (" band", 940), ("band ", 940),
        ("espn", 900), ("sportv", 880), ("premiere", 860),
        ("cnn brasil", 840), ("globonews", 830), ("globo news", 830), ("discovery", 820),
    ]
    for key, pts in brand_rules:
        if key in t:
            priority = max(priority, pts)
    return priority

def is_relevant_live_channel(row):
    title = sanitize_channel_title(row["titulo"] if isinstance(row, sqlite3.Row) else row.get("titulo", ""))
    link = (row["link"] if isinstance(row, sqlite3.Row) else row.get("link", "") or "").lower()
    if "/series/" in link or link.endswith(".mp4"):
        return False
    return classify_channel_category(title) != "Irrelevante"

def enrich_channel_row(row):
    data = dict(row) if isinstance(row, sqlite3.Row) else dict(row)
    data["titulo_limpo"] = sanitize_channel_title(data.get("titulo", ""))
    data["canal_categoria"] = data.get("canal_categoria") or classify_channel_category(data["titulo_limpo"])
    data["canal_prioridade"] = int(data.get("canal_prioridade") or 0)
    if not data["canal_prioridade"]:
        data["canal_prioridade"] = channel_brand_priority(data["titulo_limpo"]) + channel_quality_score(data["titulo_limpo"])
    data["quality_score"] = channel_quality_score(data["titulo_limpo"])
    return data

def pick_best_channels(rows, limit_per_brand=1):
    picks = {}
    ordered = sorted(rows, key=lambda r: (r["canal_prioridade"], r["quality_score"], r["titulo_limpo"]), reverse=True)
    for row in ordered:
        title = row["titulo_limpo"]
        brand = re.sub(r'\[[^\]]+\]', '', title).strip()
        brand = re.sub(r'\s{2,}', ' ', brand)
        key = normalize_text(brand)
        if not key:
            continue
        if picks.get(key, 0) >= limit_per_brand:
            continue
        picks[key] = picks.get(key, 0) + 1
        yield row

def resolve_media_cover(conn, filme):
    if not filme:
        return ""
    capa = (filme["capa"] or "").strip()
    if not _is_dead_cover(capa):
        return capa
    if filme["subgrupo"]:
        row = conn.execute(
            "SELECT capa FROM filmes WHERE subgrupo=? AND capa != '' AND capa IS NOT NULL ORDER BY id LIMIT 10",
            (filme["subgrupo"],)
        ).fetchall()
        for candidate in row:
            if candidate["capa"] and not _is_dead_cover(candidate["capa"]):
                return candidate["capa"]
    media_type = "tv" if filme["subgrupo"] or filme["genero"] in ("Seriado", "Series", "Medicina") else "movie"
    resolved = tmdb_cover_for(filme["subgrupo"] or filme["titulo"], media_type=media_type)
    return resolved or capa or ""

@app.route("/tmdb/play")
def tmdb_play():
    """Search for a TMDB title in the database and play it."""
    if not authenticated(): return redirect(url_for("login"))
    titulo = request.args.get("t", "").strip()
    tmdb_id = request.args.get("id", "").strip()
    media_type = request.args.get("m", "movie").strip() or "movie"
    release_date = request.args.get("rd", "").strip()
    capa = request.args.get("capa", "").strip()
    sinopse = request.args.get("sinopse", "").strip()
    if not titulo:
        return redirect(url_for("home"))

    future_payload = None
    if tmdb_id or is_future_release_date(release_date):
        future_payload = fetch_tmdb_trailer_payload(tmdb_id=tmdb_id, titulo=titulo, mtype=media_type)
        if not future_payload.get("poster") and capa:
            future_payload["poster"] = capa
        if not future_payload.get("sinopse") and sinopse:
            future_payload["sinopse"] = sinopse
        if not future_payload.get("release_date") and release_date:
            future_payload["release_date"] = release_date[:10]
            future_payload["release_fmt"] = format_release_date(release_date)
        future_payload["is_future"] = future_payload.get("is_future") or is_future_release_date(release_date)
        if not future_payload.get("titulo"):
            future_payload["titulo"] = titulo

    if future_payload and future_payload.get("is_future"):
        return render_template("future_release.html", item=future_payload, fallback_title=titulo)

    conn = get_db()
    filme = search_local_by_title(titulo, conn)
    conn.close()

    if filme and is_confident_local_match(titulo, filme):
        return redirect(url_for("assistir", id_filme=filme["id"]))

    if not future_payload and get_tmdb_api_key():
        future_payload = fetch_tmdb_trailer_payload(titulo=titulo, mtype=media_type)
        if future_payload.get("is_future"):
            return render_template("future_release.html", item=future_payload, fallback_title=titulo)

    flash(f'O título "{titulo}" ainda não está disponível ou não teve um match confiável no catálogo. Para evitar play incorreto, mostramos apenas resultados confirmados.', 'warning')
    return redirect(url_for("explorar", q=titulo))

@app.route("/tmdb/info/<int:tmdb_id>")
def tmdb_info(tmdb_id):
    """Get TMDB movie/TV info by ID."""
    if not authenticated(): return jsonify({"error": "Unauthorized"}), 401
    media = request.args.get("type", "movie")
    result = tmdb_request(f"/{media}/{tmdb_id}", {"language": "pt-BR"})
    if result:
        return jsonify(result)
    return jsonify({"error": "Not found"}), 404

@app.route("/proxy")
def proxy_media():
    if not authenticated(): return redirect(url_for("login"))
    target = request.args.get("url","").strip()
    if not validate_proxy_url(target): abort(400)
    headers = {
        "User-Agent": "Mozilla/5.0 (compatible; PinguimPlayer/1.0)",
        "Accept": "*/*", "Referer": target,
        "Origin": f"{request.scheme}://{request.host}",
    }
    range_h = request.headers.get("Range")
    if range_h: headers["Range"] = range_h
    try:
        req = urllib.request.Request(target, headers=headers)
        remote = urllib.request.urlopen(req, timeout=60)
    except Exception as e:
        return Response(f"Erro ao acessar midia: {e}", status=502, mimetype="text/plain")
    content_type = remote.headers.get("Content-Type","application/octet-stream")
    is_m3u8 = target.lower().endswith(".m3u8") or "mpegurl" in content_type.lower()
    if is_m3u8:
        text = remote.read().decode("utf-8", errors="ignore"); remote.close()
        return Response(rewrite_m3u8_playlist(text, target),
                        mimetype="application/vnd.apple.mpegurl",
                        headers={"Access-Control-Allow-Origin":"*","Cache-Control":"no-cache, no-store"})
    def stream():
        try:
            while True:
                chunk = remote.read(65536)
                if not chunk: break
                yield chunk
        finally:
            remote.close()
    resp_headers = {
        "Access-Control-Allow-Origin": "*",
        "Cache-Control": "no-cache" if is_live_stream(target) else "public, max-age=3600",
    }
    for h in ("Content-Length","Content-Range","Accept-Ranges","Content-Disposition","ETag"):
        v = remote.headers.get(h)
        if v: resp_headers[h] = v
    if target.lower().endswith(".ts"): content_type = "video/mp2t"
    status = getattr(remote, "status", 200)
    return Response(stream_with_context(stream()), headers=resp_headers, mimetype=content_type, status=status)

@app.route("/explorar")
def explorar():
    """
    Busca com agrupamento:
    - Séries  → 1 card por subgrupo → /serie/<nome>
    - Filmes  → deduplicados por link + variante de qualidade colapsada
    - Canais  → excluídos
    """
    if not authenticated(): return redirect(url_for("login"))
    busca     = request.args.get("q", "").strip()
    categoria = request.args.get("genero", "").strip()
    pagina    = max(1, int(request.args.get("p", 1)))
    por_pag   = 48
    conn      = get_db()

    if not busca and not categoria:
        conn.close()
        return render_template("explorar.html", busca="", categoria="",
                               itens=[], series_set=set(), total=0, pagina=1,
                               total_pag=1, formato="", section_config=SECTION_CONFIG)

    # Gêneros excluídos da busca VOD
    EXCLUIR = ("Canais",)

    # Montar cláusulas SQL
    busca_sql    = f"%{busca}%" if busca else "%"
    busca_clause = "(titulo LIKE ? OR subgrupo LIKE ?)" if busca else "1=1"
    bparams      = [busca_sql, busca_sql] if busca else []

    if categoria and categoria not in EXCLUIR:
        excl_clause = "AND genero=?"
        excl_params = [categoria]
    else:
        ph = ",".join("?" * len(EXCLUIR))
        excl_clause = f"AND genero NOT IN ({ph})"
        excl_params = list(EXCLUIR)

    # ── 1. SÉRIES agrupadas por subgrupo ─────────────────────────────────────
    series_rows = conn.execute(f"""
        SELECT
            subgrupo                                                      AS titulo,
            MIN(id)                                                       AS id,
            MIN(CASE WHEN capa NOT LIKE '%lgfp.one%'
                          AND capa NOT LIKE '%picsum%'
                          AND capa != '' AND capa IS NOT NULL
                     THEN capa END)                                       AS capa,
            genero,
            COUNT(*)                                                      AS ep_count,
            MIN(ano)                                                      AS ano,
            '' AS subgrupo, '' AS link, 0 AS ep_count_alias
        FROM filmes
        WHERE {busca_clause}
          AND subgrupo != ''
          {excl_clause}
        GROUP BY subgrupo
        ORDER BY subgrupo
        LIMIT 200
    """, bparams + excl_params).fetchall()

    # ── 2. FILMES — deduplicados por link (mesmo arquivo = mesma entrada) ────
    FILMES_GENRES = ("Filmes","Comédia","Ação","Terror","Animações","Família",
                     "Documentários","Marvel","Disney","HBO","Prime","Netflix",
                     "Stand Up Commedy","GamePlay","Medicina")

    if categoria and categoria in FILMES_GENRES:
        fg_clause = "AND genero=?"
        fg_params = [categoria]
    elif categoria:
        fg_clause = "AND 1=0"
        fg_params = []
    else:
        ph = ",".join("?" * len(FILMES_GENRES))
        fg_clause = f"AND genero IN ({ph})"
        fg_params = list(FILMES_GENRES)

    filmes_raw = conn.execute(f"""
        SELECT
            titulo,
            MIN(id)  AS id,
            MIN(CASE WHEN capa NOT LIKE '%lgfp.one%'
                          AND capa NOT LIKE '%picsum%'
                          AND capa != '' AND capa IS NOT NULL
                     THEN capa END)                  AS capa,
            COALESCE(
                MIN(CASE WHEN genero='Filmes'    THEN genero END),
                MIN(CASE WHEN genero='Animações' THEN genero END),
                MIN(genero)
            )                                        AS genero,
            MIN(ano)                                 AS ano,
            link,
            '' AS subgrupo,
            0  AS ep_count
        FROM filmes
        WHERE {busca_clause}
          AND (subgrupo IS NULL OR subgrupo = '')
          {fg_clause}
        GROUP BY link
        ORDER BY titulo, genero
        LIMIT 400
    """, bparams + fg_params).fetchall()

    conn.close()

    # Segunda passagem: colapsar variantes de qualidade (4K, HDR, FHD…)
    # Gêneros com conteúdo próprio mantêm bucket separado
    DISTINCT_GENRES = {"Animações","Família","Documentários","Medicina",
                       "Marvel","Disney","Stand Up Commedy","GamePlay"}

    def _clean(t):
        import re as _r
        # Remove qualidade entre colchetes: [HDR], [4K], [FHD], etc
        t = _r.sub(r"\s*\[(?:FHD|HD|SD|4K|H265|HDR|HEVC|UHD|WEBDL|BLURAY|BDRIP)[^\]]*\]", "", t, flags=_r.I)
        # Remove sufixo de qualidade após espaço: "Título 4K" → "Título"
        t = _r.sub(r"\s+(?:4K|FHD|HDR|H265|HEVC|UHD|SD|HD|WEBDL|BLURAY|BDRIP)(?:[^a-zA-Z].*)?$", "", t, flags=_r.I)
        # Remove ano entre parênteses no fim: "Título (2007)" → "Título"
        t = _r.sub(r"\s*\(\d{4}\)\s*$", "", t)
        return t.strip().lower()

    def _bucket(g):
        return g if g in DISTINCT_GENRES else "vod"

    seen, filmes_dedup = set(), []
    for r in filmes_raw:
        k = (_clean(r["titulo"]), _bucket(r["genero"]))
        if k not in seen:
            seen.add(k)
            filmes_dedup.append(r)

    # Combinar e paginar
    combined  = list(series_rows) + filmes_dedup
    total     = len(combined)
    offset    = (pagina - 1) * por_pag
    total_pag = max(1, (total + por_pag - 1) // por_pag)
    page_items = combined[offset: offset + por_pag]
    series_set = {r["titulo"] for r in series_rows}

    return render_template("explorar.html",
        busca=busca, categoria=categoria,
        itens=page_items, series_set=series_set,
        total=total, pagina=pagina, total_pag=total_pag,
        formato="", section_config=SECTION_CONFIG)


@app.route("/api/items")
def api_items():
    if not authenticated(): return jsonify({"items": []}), 401
    raw = request.args.get("ids","").strip()
    ids = [int(x) for x in raw.split(",") if x.strip().isdigit()]
    if not ids: return jsonify({"items": []})
    conn = get_db()
    rows = conn.execute(f"SELECT * FROM filmes WHERE id IN ({','.join('?'*len(ids))})", ids).fetchall()
    cache_rows = conn.execute(
        f"SELECT * FROM user_media_cache WHERE user_id=? AND media_id IN ({','.join('?'*len(ids))})",
        [session["user_id"]] + ids
    ).fetchall()
    conn.close()
    cache_map = {r["media_id"]: dict(r) for r in cache_rows}
    items = []
    for row in rows:
        item = dict(row)
        cached = cache_map.get(item["id"], {})
        item["cached_poster_url"] = cached.get("poster_url", "")
        item["cached_series_poster_url"] = cached.get("series_poster_url", "")
        item["resolved_capa"] = cached.get("series_poster_url") or cached.get("poster_url") or item.get("capa", "")
        items.append(item)
    return jsonify({"items": items})

@app.route("/admin/importar", methods=["GET","POST"])
def importar_m3u():
    if not authenticated(): return redirect(url_for("login"))
    msg = erro = None
    if request.method == "POST":
        acao   = request.form.get("acao","url")
        limpar = request.form.get("limpar") == "1"
        try:
            import uuid as _uuid
            job_id = _uuid.uuid4().hex
            if acao == "url":
                m3u_url = request.form.get("m3u_url","").strip()
                if not validate_url(m3u_url): raise ValueError("URL invalida.")
                t = _threading.Thread(target=_run_import_job,
                    args=(job_id, m3u_url, m3u_url, limpar), daemon=True)
                t.start()
                msg = f"__JOB__{job_id}"   # frontend polls /api/import-status/<job_id>
            else:
                f = request.files.get("arquivo")
                if not f or not f.filename: raise ValueError("Selecione um arquivo .m3u.")
                content = f.read().decode("utf-8", errors="ignore")
                t = _threading.Thread(target=_run_import_job,
                    args=(job_id, content, f.filename, limpar), daemon=True)
                t.start()
                msg = f"__JOB__{job_id}"
        except Exception as e:
            erro = f"Falha: {e}"
    conn = get_db()
    stats = {nome: conn.execute("SELECT COUNT(*) FROM filmes WHERE genero=?",(nome,)).fetchone()[0]
             for nome in SECTION_CONFIG}
    total_db = conn.execute("SELECT COUNT(*) FROM filmes").fetchone()[0]
    tmdb_synced = conn.execute("SELECT COUNT(*) FROM filmes WHERE tmdb_id > 0").fetchone()[0]
    conn.close()
    return render_template("importar.html", msg=msg, erro=erro, stats=stats,
                           total_db=total_db, tmdb_synced=tmdb_synced)

