@app.route("/login/token")
def login_via_token():
    """GET endpoint: auto-login via token URL. Redirect to home after."""
    token = request.args.get("t","").strip()
    if not token: return redirect(url_for("login"))
    conn = get_db()
    u = conn.execute("SELECT * FROM usuarios WHERE access_token=? AND access_token!=''", (token,)).fetchone()
    conn.close()
    if not u: return redirect(url_for("login"))
    session["user_id"]  = u["id"]
    session["username"] = u["username"]
    # Auto-import playlist if linked and DB is empty for this user
    if u["playlist_url"]:
        conn2 = get_db()
        total = conn2.execute("SELECT COUNT(*) FROM filmes").fetchone()[0]
        conn2.close()
        if total == 0:
            import uuid as _uuid
            job_id = _uuid.uuid4().hex
            t = _threading.Thread(target=_run_import_job,
                args=(job_id, u["playlist_url"], u["playlist_url"], True), daemon=True)
            t.start()
    return redirect(url_for("home"))



