_fix_capas_status = {"running": False, "found": 0, "not_found": 0, "total": 0, "done": 0, "log": []}

@app.route("/fix-capas")
def fix_capas_page():
    """Dashboard para corrigir capas mortas via browser."""
    if not authenticated(): return redirect(url_for("login"))
    conn = get_db()
    dead = conn.execute(
        "SELECT COUNT(*) FROM filmes WHERE (capa LIKE '%lgfp.one%' OR capa LIKE '%goo.gl%' OR "
        "capa LIKE '%picsum.photos%' OR capa='' OR capa IS NULL) AND genero != 'Canais'"
    ).fetchone()[0]
    total = conn.execute("SELECT COUNT(*) FROM filmes WHERE genero != 'Canais'").fetchone()[0]
    conn.close()
    pct_ok = round((total - dead) * 100 / max(total, 1), 1)
    return render_template_string(FIX_CAPAS_HTML, dead=dead, total=total, pct_ok=pct_ok,
                                   status=_fix_capas_status)

@app.route("/api/fix-capas/start", methods=["POST"])
def api_fix_capas_start():
    """Inicia background job para corrigir capas."""
    if not authenticated(): return jsonify({"error": "Unauthorized"}), 401
    if _fix_capas_status["running"]:
        return jsonify({"error": "Já rodando"}), 409
    import threading
    workers = int(request.json.get("workers", 3)) if request.json else 3
    limit   = request.json.get("limit") if request.json else None
    t = threading.Thread(target=_fix_capas_worker, args=(workers, limit), daemon=True)
    t.start()
    return jsonify({"started": True})

@app.route("/api/fix-capas/status")
def api_fix_capas_status():
    if not authenticated(): return jsonify({}), 401
    return jsonify(_fix_capas_status)

def _fix_capas_worker(workers=3, limit=None):
    import concurrent.futures as _cf
    global _fix_capas_status
    _fix_capas_status.update({"running": True, "found": 0, "not_found": 0, "done": 0, "log": []})

    def log(msg):
        _fix_capas_status["log"] = (_fix_capas_status["log"] + [msg])[-50:]

    api_key = get_tmdb_api_key()
    conn = sqlite3.connect(str(DB_PATH))
    conn.row_factory = sqlite3.Row

    dead_clause = ("capa LIKE '%lgfp.one%' OR capa LIKE '%goo.gl%' OR capa LIKE '%picsum.photos%' "
                   "OR capa LIKE '%bit.ly%' OR capa LIKE '%tinyurl.com%' OR capa='' OR capa IS NULL")

    series_q = conn.execute(
        f"SELECT DISTINCT subgrupo FROM filmes WHERE ({dead_clause}) AND genero IN ('Seriado','Medicina') AND subgrupo!=''"
    ).fetchall()
    filmes_q = conn.execute(
        f"SELECT DISTINCT titulo, genero FROM filmes WHERE ({dead_clause}) AND genero NOT IN ('Seriado','Medicina','Canais')"
    ).fetchall()
    conn.close()

    if limit:
        series_q = series_q[:limit // 2]
        filmes_q = filmes_q[:limit - len(series_q)]

    total = len(series_q) + len(filmes_q)
    _fix_capas_status["total"] = total
    log(f"Iniciando: {len(series_q)} séries + {len(filmes_q)} filmes")

    db_lock = __import__("threading").Lock()

    def db_update_serie(updates):
        if not updates: return
        with db_lock:
            uc = sqlite3.connect(str(DB_PATH))
            uc.executemany("UPDATE filmes SET capa=?, backdrop=? WHERE subgrupo=? AND genero IN ('Seriado','Medicina')", updates)
            uc.commit(); uc.close()

    def db_update_filme(updates):
        if not updates: return
        with db_lock:
            uc = sqlite3.connect(str(DB_PATH))
            uc.executemany("UPDATE filmes SET capa=?, backdrop=? WHERE titulo=? AND genero NOT IN ('Seriado','Medicina','Canais')", updates)
            uc.commit(); uc.close()

    # Series
    batch = []
    with _cf.ThreadPoolExecutor(max_workers=workers) as ex:
        futs = {ex.submit(tmdb_cover_for, r["subgrupo"], "tv"): r["subgrupo"] for r in series_q}
        for fut in _cf.as_completed(futs):
            sg = futs[fut]
            url = fut.result()
            _fix_capas_status["done"] += 1
            if url:
                batch.append((url, "", sg))
                _fix_capas_status["found"] += 1
                log(f"✅ {sg[:50]}")
            else:
                _fix_capas_status["not_found"] += 1
            if len(batch) >= 50:
                db_update_serie(batch); batch = []
    db_update_serie(batch); batch = []

    # Filmes
    with _cf.ThreadPoolExecutor(max_workers=workers) as ex:
        futs = {ex.submit(tmdb_cover_for, r["titulo"], "movie"): r["titulo"] for r in filmes_q}
        for fut in _cf.as_completed(futs):
            titulo = futs[fut]
            url = fut.result()
            _fix_capas_status["done"] += 1
            if url:
                batch.append((url, "", titulo))
                _fix_capas_status["found"] += 1
                log(f"✅ {titulo[:50]}")
            else:
                _fix_capas_status["not_found"] += 1
                log(f"❌ {titulo[:50]}")
            if len(batch) >= 50:
                db_update_filme(batch); batch = []
    db_update_filme(batch)

    _fix_capas_status["running"] = False
    log(f"Concluído! ✅ {_fix_capas_status['found']} encontradas | ❌ {_fix_capas_status['not_found']} não encontradas")

