# ── Image Proxy ─────────────────────────────────────────────────────────────
@app.route("/img-proxy")
def img_proxy():
    """
    Proxy de imagens externas para evitar bloqueios de CORS/hotlinking.
    Uso: /img-proxy?u=https://image.tmdb.org/...
    Cache de 7 dias no browser.
    """
    if not authenticated(): return "", 401
    url = request.args.get("u", "").strip()
    if not url or not url.startswith("http"):
        abort(400)
    # Whitelist de domínios permitidos
    ALLOWED = ["image.tmdb.org", "m.media-amazon.com", "is4.mzstatic.com",
               "is1.mzstatic.com", "is2.mzstatic.com", "is3.mzstatic.com",
               "img.omdbapi.com"]
    from urllib.parse import urlparse
    host = urlparse(url).netloc
    if not any(a in host for a in ALLOWED):
        abort(403)
    try:
        req = urllib.request.Request(url, headers={
            "User-Agent": "Mozilla/5.0 (compatible; PinguimProxy/1.0)",
            "Referer": "https://www.themoviedb.org/"
        })
        with urllib.request.urlopen(req, timeout=8) as r:
            data   = r.read()
            ctype  = r.headers.get("Content-Type", "image/jpeg")
    except Exception:
        abort(502)
    resp = Response(data, content_type=ctype)
    resp.headers["Cache-Control"] = "public, max-age=604800, immutable"
    resp.headers["X-Proxy"] = "pinguim"
    return resp

@app.route("/api/cache/status")
def api_cache_status():
    """Retorna status dos caches: TMDB disco + covers em memória."""
    if not authenticated(): return jsonify({}), 401
    tmdb_age = None
    tmdb_items = 0
    if TMDB_CACHE_FILE.exists():
        try:
            raw = json_mod.loads(TMDB_CACHE_FILE.read_text(encoding="utf-8"))
            tmdb_age   = round((time.time() - raw.get("timestamp", 0)) / 3600, 1)
            tmdb_items = sum(len(v) for v in raw.get("data", {}).values() if isinstance(v, list))
        except Exception:
            pass
    return jsonify({
        "tmdb_cache": {
            "file":       str(TMDB_CACHE_FILE),
            "age_hours":  tmdb_age,
            "items":      tmdb_items,
            "ttl_hours":  TMDB_CACHE_TTL // 3600,
            "stale_hours":TMDB_CACHE_STALE // 3600,
            "bg_refresh": _tmdb_bg_refresh,
        },
        "cover_cache": {
            "entries":    len(_cover_cache),
            "max":        _COVER_CACHE_MAX,
            "ttl_hours":  _COVER_CACHE_TTL // 3600,
        }
    })
